342	            base.Prepare(false);
343	            int i = 0;
344	            do {
345	                art::ArtMethod method(base.Ptr() + i * SIZEOF(ArtMethod), base);
346	                if (fn(method)) break;
347	                i++;
348	            } while(i < size);
349	        }
